1	/**
2	 * LAYERINFINITE — lib/ingest-core.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Shared outcome insertion logic reused by:
5	 *   - log-outcome route (SDK real-time ingestion)
6	 *   - import route (historical file upload ingestion)
7	 *
8	 * Extracts the data pipeline from the HTTP layer so both callers
9	 * get identical normalization, FK resolution, quality scoring,
10	 * and DB insertion without duplicated logic.
11	 *
12	 * KEY INVARIANT: ingestion_source must always be set by the caller.
13	 *   'sdk'    → real-time SDK outcome
14	 *   'import' → historical file upload
15	 *   'mcp'    → V2 gateway proxy outcome
16	 *
17	 * Trust side-effects (orchestrateOutcome + upsertLiveTrustScore)
18	 * are NEVER triggered for 'import' rows — controlled via skipTrustUpdate.
19	 * ══════════════════════════════════════════════════════════════
20	 */
21	
22	import crypto from 'node:crypto';
23	import { supabase } from './supabase.js';
24	import { invalidateCache, getCachedScore } from './scoring.js';
25	import { orchestrateOutcome } from './outcome-orchestrator.js';
26	import { resolveVerifiedSuccess } from './verifier.js';
27	import { inferTask, isGenericTaskName, validateTaskName, TASK_MAPPING_CONFIDENCE } from './recommendation/task-infer.js';
28	import type { TaskInferResult, TaskMappingTier } from './recommendation/task-infer.js';
29	import { inferSemanticActionCluster } from './recommendation/semantic-action-cluster.js';
30	import type { SemanticActionClusterResult } from './recommendation/semantic-action-cluster.js';
31	import { sanitizeContext, sanitizeString } from './sanitize.js';
32	import * as contextEmbed from './context-embed.js';
33	import {
34	    inferOutcomeScore,
35	    fetchActionBaseline,
36	    invalidateActionBaselineCache,
37	} from './outcome-score-inference.js';
38	import type { InferredOutcomeScore } from './outcome-score-inference.js';
39	
40	// ── Types ─────────────────────────────────────────────────────
41	
42	export type IngestionSource = 'sdk' | 'import' | 'mcp';
43	export type ExecutionStatus = 'COMPLETED' | 'FAILED';
44	export type StatusOrigin =
45	    | 'explicit'
46	    | 'inferred_from_success'
47	    | 'inferred_from_score'
48	    | 'reconciled_feedback';
49	
50	export interface IngestCoreOptions {

30	
31	// ── Data sources summary ──────────────────────────────────────
32	// Counts SDK vs imported outcomes for the agent so the client
33	// can show "Based on 248 uploaded + 42 SDK outcomes, quality 0.71"
34	async function fetchDataSources(
35	    customerId: string,
36	    agentId: string,
37	    taskName: string,
38	): Promise<{
39	    uploaded_outcomes: number;
40	    sdk_outcomes: number;
41	    mcp_outcomes: number;
42	    total: number;
43	    upload_share: number;
44	    quality_score: number | null;
45	}> {
46	    try {
47	        const normalizedTask = normalizeTaskSlug(taskName);
48	        const candidates = normalizedTask && normalizedTask !== taskName
49	            ? [taskName, normalizedTask]
50	            : [taskName];
51	
52	        let finalCandidate = candidates[0];
53	        let importedCount = 0;
54	        let sdkCount = 0;
55	        let mcpCount = 0;
56	
57	        for (const candidate of candidates) {
58	            const baseQuery = supabase
59	                .from('fact_outcomes')
60	                .select('*', { count: 'exact', head: true })
61	                .eq('customer_id', customerId)
62	                .eq('agent_id', agentId)
63	                .eq('task_name', candidate)
64	                .eq('is_synthetic', false)
65	                .eq('is_deleted', false);
66	
67	            const [importRes, sdkRes, mcpRes] = await Promise.all([
68	                baseQuery.eq('ingestion_source', 'import'),
69	                baseQuery.eq('ingestion_source', 'api'),
70	                baseQuery.eq('ingestion_source', 'mcp')
71	            ]);
72	            
73	            // If we found data using this slug, stick with it.
74	            if ((importRes.count ?? 0) > 0 || (sdkRes.count ?? 0) > 0 || (mcpRes.count ?? 0) > 0) {
75	                importedCount = importRes.count ?? 0;
76	                sdkCount = sdkRes.count ?? 0;
77	                mcpCount = mcpRes.count ?? 0;
78	                finalCandidate = candidate;
79	                break;
80	            }
81	        }
82	
83	        const total = importedCount + sdkCount + mcpCount;
84	        if (total === 0) {
85	            return { uploaded_outcomes: 0, sdk_outcomes: 0, mcp_outcomes: 0, total: 0, upload_share: 0, quality_score: null };
86	        }
87	
88	        // Fetch just a 1000-row sample for the average quality to prevent OOM
89	        const { data: qualityRows } = await supabase
90	            .from('fact_outcomes')
91	            .select('data_quality')
92	            .eq('customer_id', customerId)
93	            .eq('agent_id', agentId)
94	            .eq('task_name', finalCandidate)
95	            .eq('is_synthetic', false)
96	            .eq('is_deleted', false)
97	            .not('data_quality', 'is', 'null')
98	            .order('timestamp', { ascending: false })
99	            .limit(1000);
100	
101	        let qualityScore = null;
102	        if (qualityRows && qualityRows.length > 0) {
103	            const sum = qualityRows.reduce((acc, row) => acc + (Number(row.data_quality) || 0), 0);
104	            qualityScore = Math.round((sum / qualityRows.length) * 10000) / 10000;
105	        }
106	
107	        const uploadShare = Math.round((importedCount / total) * 10000) / 10000;
108	
109	        return { uploaded_outcomes: importedCount, sdk_outcomes: sdkCount, mcp_outcomes: mcpCount, total, upload_share: uploadShare, quality_score: qualityScore };
110	    } catch {
111	        return { uploaded_outcomes: 0, sdk_outcomes: 0, mcp_outcomes: 0, total: 0, upload_share: 0, quality_score: null };
112	    }
113	}
